SELECT bs_per_bldg.geometry_building_type_recs, sum(bs_per_bldg.tract_count) AS sample_count, sum(bs_per_bldg.bldg_weight) AS units_count, sum(ts_aggr._inner_rows) / CAST(count(distinct(ts_aggr.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(ts_aggr."bs__out.electricity.total.energy_consumption" * bs_per_bldg.bldg_weight) AS "electricity.total.energy_consumption", sum(ts_aggr."bs__out.natural_gas.total.energy_consumption" * bs_per_bldg.bldg_weight) AS "natural_gas.total.energy_consumption" FROM (SELECT ts_flat.timestamp AS timestamp, ts_flat.bldg_id AS bldg_id, sum(ts_flat."_v__out.electricity.total.energy_consumption") AS "bs__out.electricity.total.energy_consumption", sum(ts_flat."_v__out.natural_gas.total.energy_consumption") AS "bs__out.natural_gas.total.energy_consumption", count(*) AS _inner_rows FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, date_trunc('year', date_add('second', -900, resstock_2024_amy2018_release_2_by_state_vu.timestamp)) AS timestamp, resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" AS "_v__out.electricity.total.energy_consumption", resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" AS "_v__out.natural_gas.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade IN (1) AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO' AND resstock_2024_amy2018_release_2_by_state_vu.bldg_id IN (SELECT bs.bldg_id FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.upgrade IN (1, 2) AND bs.applicability = true GROUP BY bs.bldg_id HAVING count(distinct(bs.upgrade)) = 2)) AS ts_flat GROUP BY ts_flat.timestamp, ts_flat.bldg_id) AS ts_aggr JOIN (SELECT bs.bldg_id AS bldg_id, arbitrary(bs."in.geometry_building_type_recs") AS geometry_building_type_recs, sum(bs.weight) AS bldg_weight, count(*) AS tract_count FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.upgrade = 0 AND bs."in.state" = 'CO' GROUP BY bs.bldg_id) AS bs_per_bldg ON bs_per_bldg.bldg_id = ts_aggr.bldg_id GROUP BY 1 ORDER BY 1